1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_BASE_PREMIUM = 60;
5	
6	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const withFirstInsurance = (base: number): number =>
18	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
19	
20	const groupBase = (type: string, count: number): number => {
21	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
22	    return withFirstInsurance(BLOCK_BASE_PREMIUM);
23	  }
24	  return count * withFirstInsurance(BASE_PREMIUM[type]);
25	};
26	
27	const INSURANCE_VALUE: Record<string, number> = {
28	  sword: 1000,
29	  amulet: 600,
30	  staff: 800,
31	  potion: 400,
32	  rune: 250,
33	  moonstone: 250,
34	};
35	
36	const DEDUCTIBLE = 100;
37	
38	export const runScenario = (input: any): { results: unknown[] } => {
39	  const results: unknown[] = [];
40	  const policies: { items: any[]; cap: number; remainingCap: number }[] = [];
41	  for (let stepIndex = 0; stepIndex < input.steps.length; stepIndex++) {
42	    const step = input.steps[stepIndex];
43	    if (step.op === "claim") {
44	      const policy = policies[step.policy];
45	      let totalPayout = 0;
46	      for (const damage of step.incident.damages) {
47	        const policyItem = policy.items.find((it) => it.type === damage.itemType);
48	        let reimbursement = damage.amount;
49	        if (policyItem && policyItem.enchantment >= 8) {
50	          reimbursement = 0.5 * damage.amount;
51	        }
52	        const payout = Math.max(0, reimbursement - DEDUCTIBLE);
53	        totalPayout += payout;
54	      }
55	      const cappedPayout = Math.min(totalPayout, policy.remainingCap);
56	      policy.remainingCap -= cappedPayout;
57	      results.push({ payout: Math.floor(cappedPayout), remainingCap: policy.remainingCap });
58	      continue;
59	    }
60	    const items: { type: string; cursed?: boolean }[] = step.items;
61	    const countsByType = new Map<string, number>();
62	    for (const item of items) {
63	      countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
64	    }
65	    let premium = PROCESSING_FEE;
66	    let policyBase = 0;
67	    for (const [type, count] of countsByType) {
68	      premium += groupBase(type, count);
69	      policyBase += count * BASE_PREMIUM[type];
70	    }
71	    if (input.customer?.yearsWithMHPCO >= 2) {
72	      premium -= 0.2 * policyBase;
73	    }
74	    if (stepIndex >= 1) {
75	      premium -= 0.15 * policyBase;
76	    }
77	    for (const item of items) {
78	      if (item.cursed) {
79	        premium += 0.5 * BASE_PREMIUM[item.type];
80	      }
81	      if ((item as any).enchantment >= 5) {
82	        premium += 0.3 * BASE_PREMIUM[item.type];
83	      }
84	    }
85	    let insuranceSum = 0;
86	    for (const item of items) {
87	      insuranceSum += INSURANCE_VALUE[item.type];
88	    }
89	    const cap = 2 * insuranceSum;
90	    policies.push({ items, cap, remainingCap: cap });
91	    results.push({ premium: Math.ceil(premium) });
92	  }
93	  return { results };
94	};
